  ('social-worker-moex-03267', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Newman及Newman（2006）所言，嬰幼兒的學習多數來自於感覺系統協助產生的傾聽和觀 察，有關嬰幼兒感覺系統說明，下列何者正確？', '["嬰幼兒的感覺系統僅包含聽覺、視覺與味覺等子系統", "各感覺子系統之間是互相聯繫的", "味覺是最早與外在環境產生連結的感覺子系統", "視覺的發展較慢，要到約10個月時，嬰幼兒才能看見與成年人相同的事物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03268', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在成年晚期，無論個體的健康狀態是否良好，其生理功能都會逐漸衰退，下列有關「生殖系統」 功能衰退的敘述，何者正確？', '["男性沒有更年期", "只有女性的生殖器官會出現萎縮退化的狀態", "因生殖系統的衰退，女性會完全失去生育力", "因生殖系統的衰退，男性會完全失去生育力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03269', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '神經元系統是重要的生理系統之一，各類神經元系統的發展都對人的生理、心理與社會功能產生 影響，其中大腦神經突觸及軸突就與大腦功能有密切關聯，人的大腦重量一般在個體出生後最早 幾個月時，達到最後成熟重量的一半？', '["6個月", "18個月", "36個月", "48個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
